// Extract execution data from n8n API response
const executions = $input.all();
const data = executions[0].json.data || executions[0].json;

// Handle both array and object responses
const execList = Array.isArray(data) ? data : (data.data || []);

// Get last 24 hours of executions
const dayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
const recent = execList.filter(e => e.startedAt && e.startedAt > dayAgo);

const records = recent.map(e => ({
  workflow_id: e.workflowId,
  workflow_name: e.workflowName || 'Unknown',
  status: e.succeeded ? 'success' : (e.stopped ? 'stopped' : 'running'),
  started_at: e.startedAt,
  finished_at: e.finishedAt || null,
  duration_ms: e.finishedAt && e.startedAt 
    ? new Date(e.finishedAt) - new Date(e.startedAt) 
    : null,
  error: e.error || null,
  execution_count: 1
}));

return records.map(r => ({ json: r }));

// Aggregate execution stats for Slack notification
const executions = $input.all();

const stats = {
  total: executions.length,
  success: executions.filter(e => e.json.status === 'success').length,
  failed: executions.filter(e => e.json.status !== 'success').length,
  avgDuration: executions.length > 0 
    ? Math.round(executions.reduce((s, e) => s + (e.json.duration_ms || 0), 0) / executions.length)
    : 0
};

const message = `*n8n Workflow Stats (24h)*\n` +
  `Total: ${stats.total} | ✅ ${stats.success} | ❌ ${stats.failed}\n` +
  `Avg Duration: ${(stats.avgDuration / 1000).toFixed(1)}s`;

return [{ json: { text: message } }];
